% the iris dataset is a set of 150 records with 4 features and 3 targets.
% iris_dataset contains: irisInputs 150x4 double, irisTargets 150x3 double.
% find(condition, 1) returns first index for which condition holds.
load iris_dataset;

model1 = mnrfit(irisInputs, irisTargets);

[loadings, scores, variance] = pca(irisInputs);
irisInputs2 = scores(:,1:3);
model2 = mnrfit(irisInputs2, irisTargets);

perc_variance = cumsum(variance) / sum(variance);
vv = find(perc_variance >= 0.95, 1);
irisInputs3 = scores(:,1:vv);
model3 = mnrfit(irisInputs3, irisTargets);
